import React, { useState } from "react";
import ModelSelector from "../components/ModelSelector";
import HyperParameters from "../components/HyperParameters";
import TrainingResults from "../components/TrainingResults";
import RandomForestAnalysis from "../components/RandomForestAnalysis";
import { trainModel, uploadDataset } from "../services/api";

const NAV_TABS = [
  { id: "train", label: "Entraînement", icon: "🚀" },
  { id: "tache4", label: "Tâche 4 — RF", icon: "🌲" },
  { id: "history", label: "Historique", icon: "📜" },
];

export default function Dashboard({
  allResults,
  onTrainComplete,
  onNotify,
}) {
  const [selectedModels, setSelectedModels] = useState([
    "random_forest",
  ]);

  const [compareMode, setCompareMode] = useState(false);
  const [training, setTraining] = useState(false);
  const [progress, setProgress] = useState(0);
  const [params, setParams] = useState({});
  const [navTab, setNavTab] = useState("train");

  const activeModel = selectedModels[0];

  const updateParams = (newParams) =>
    setParams((prev) => ({
      ...prev,
      [activeModel]: newParams,
    }));

  const handleTrain = async () => {
    setTraining(true);
    setProgress(0);

    try {
      const results = {};

      for (const m of selectedModels) {
        const res = await trainModel({
          model: m,
          hyperparams: params[m] || {},
        });

        results[m] = res;

        setProgress(
          (prev) => prev + 100 / selectedModels.length
        );
      }

      setProgress(100);

      onTrainComplete(results);

      onNotify(
        "✅ Entraînement terminé !",
        "success"
      );
    } catch (err) {
      onNotify(
        "❌ Erreur d'entraînement",
        "error"
      );
    } finally {
      setTraining(false);
      setProgress(0);
    }
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];

    if (!file) return;

    const formData = new FormData();
    formData.append("file", file);

    try {
      await uploadDataset(formData);

      onNotify(
        "✅ Dataset uploadé !",
        "success"
      );
    } catch {
      onNotify(
        "❌ Échec de l'upload",
        "error"
      );
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 via-blue-50 to-cyan-100 relative overflow-hidden">

      {/* Background Decorations */}
      <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-cyan-300/30 rounded-full blur-[140px]" />
      <div className="absolute bottom-0 right-0 w-[500px] h-[500px] bg-purple-300/30 rounded-full blur-[140px]" />
      <div className="absolute top-[40%] left-[40%] w-[300px] h-[300px] bg-blue-300/20 rounded-full blur-[120px]" />

      {/* NAVBAR */}
      <div className="sticky top-0 z-50 backdrop-blur-2xl bg-white/60 border-b border-white/40 shadow-lg">

        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">

          {/* LOGO */}
          <div>
            <h1 className="text-3xl font-black bg-gradient-to-r from-cyan-600 via-blue-600 to-purple-600 bg-clip-text text-transparent">
              AI ML Dashboard
            </h1>

            <p className="text-sm text-slate-500 mt-1">
              Advanced Machine Learning Platform
            </p>
          </div>

          {/* NAV TABS */}
          <div className="flex items-center gap-3">

            {NAV_TABS.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setNavTab(tab.id)}
                className={`px-6 py-3 rounded-2xl text-sm font-bold transition-all duration-300 backdrop-blur-xl
                ${
                  navTab === tab.id
                    ? "bg-gradient-to-r from-cyan-500 to-blue-500 text-white shadow-xl scale-105"
                    : "bg-white/50 text-slate-600 hover:bg-white hover:shadow-lg"
                }`}
              >
                <span className="mr-2">
                  {tab.icon}
                </span>

                {tab.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* MAIN */}
      <div className="max-w-7xl mx-auto px-6 py-10 relative z-10">

        {/* ================= TRAIN ================= */}
        {navTab === "train" && (
          <div className="grid grid-cols-1 lg:grid-cols-[350px_1fr] gap-8">

            {/* LEFT */}
            <div className="space-y-6">

              {/* MODEL SELECTOR */}
              <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-7 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

                <div className="mb-5">
                  <h2 className="text-xl font-black text-slate-800">
                    🤖 Models
                  </h2>

                  <p className="text-sm text-slate-500 mt-1">
                    Configure your machine learning models
                  </p>
                </div>

                <ModelSelector
                  selected={selectedModels}
                  onChange={setSelectedModels}
                  compareMode={compareMode}
                  onCompareModeChange={
                    setCompareMode
                  }
                />
              </div>

              {/* HYPERPARAMETERS */}
              <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-7 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

                <div className="mb-5">
                  <h2 className="text-xl font-black text-slate-800">
                    ⚙ Hyperparameters
                  </h2>

                  <p className="text-sm text-slate-500 mt-1">
                    Fine tuning settings
                  </p>
                </div>

                <HyperParameters
                  modelId={activeModel}
                  params={
                    params[activeModel] || {}
                  }
                  onChange={updateParams}
                  onNotify={onNotify}
                />
              </div>

              {/* DATASET */}
              <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-7 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

                <h2 className="text-xl font-black text-slate-800 mb-5">
                  📂 Dataset Upload
                </h2>

                <label className="group flex flex-col items-center justify-center gap-4 border-2 border-dashed border-cyan-200 hover:border-cyan-500 rounded-3xl p-10 transition-all cursor-pointer bg-gradient-to-br from-cyan-50 to-blue-50 hover:shadow-xl">

                  <div className="text-6xl group-hover:scale-110 transition-all duration-300">
                    ☁️
                  </div>

                  <div className="text-center">
                    <p className="font-bold text-slate-700 text-lg">
                      Upload Dataset
                    </p>

                    <p className="text-sm text-slate-500 mt-1">
                      CSV • DATA • Excel
                    </p>
                  </div>

                  <input
                    type="file"
                    className="hidden"
                    onChange={handleUpload}
                    accept=".csv,.data"
                  />
                </label>
              </div>

              {/* TRAIN BUTTON */}
              <button
                onClick={handleTrain}
                disabled={training}
                className="w-full py-5 rounded-3xl bg-gradient-to-r from-cyan-500 via-blue-500 to-purple-500 text-white text-lg font-black shadow-[0_10px_40px_rgba(59,130,246,0.4)] hover:scale-[1.02] transition-all duration-300 disabled:opacity-50"
              >
                {training ? (
                  <div className="flex items-center justify-center gap-3">
                    <svg
                      className="animate-spin h-5 w-5"
                      viewBox="0 0 24 24"
                      fill="none"
                    >
                      <circle
                        cx="12"
                        cy="12"
                        r="10"
                        stroke="currentColor"
                        strokeOpacity="0.3"
                        strokeWidth="3"
                      />

                      <path
                        d="M12 2a10 10 0 0 1 10 10"
                        stroke="currentColor"
                        strokeWidth="3"
                        strokeLinecap="round"
                      />
                    </svg>

                    Training...
                    {Math.round(progress)}%
                  </div>
                ) : (
                  "🚀 Launch Training"
                )}
              </button>

              {/* PROGRESS */}
              {training && (
                <div className="h-3 bg-white rounded-full overflow-hidden shadow-inner">
                  <div
                    className="h-full bg-gradient-to-r from-cyan-500 to-blue-500 rounded-full transition-all duration-300"
                    style={{
                      width: `${progress}%`,
                    }}
                  />
                </div>
              )}
            </div>

            {/* RIGHT */}
            <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-8 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

              <div className="flex items-center justify-between mb-8">

                <div>
                  <h2 className="text-3xl font-black text-slate-800">
                    📊 Training Results
                  </h2>

                  <p className="text-slate-500 mt-2">
                    Real-time model evaluation and analytics
                  </p>
                </div>

                <div className="px-5 py-2 rounded-2xl bg-emerald-100 text-emerald-700 font-bold text-sm shadow">
                  LIVE
                </div>
              </div>

              <TrainingResults
                results={allResults}
                onNotify={onNotify}
              />
            </div>
          </div>
        )}

        {/* ================= TACHE 4 ================= */}
        {navTab === "tache4" && (
          <div className="grid grid-cols-1 lg:grid-cols-[1fr_400px] gap-8">

            {/* ANALYSIS */}
            <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-8 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">
              <RandomForestAnalysis
                trainingResults={allResults}
              />
            </div>

            {/* SIDEBAR */}
            <div className="space-y-6">

              {/* METRICS */}
              <div className="bg-gradient-to-br from-emerald-100 to-cyan-100 border border-white/40 rounded-[32px] p-8 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

                <h3 className="text-2xl font-black text-emerald-700 mb-6">
                  🌲 RF Metrics
                </h3>

                <div className="space-y-4">

                  {[
                    {
                      label: "Accuracy",
                      val:
                        allResults
                          ?.random_forest
                          ?.accuracy ?? 69.5,
                    },

                    {
                      label: "F1 Score",
                      val:
                        allResults
                          ?.random_forest
                          ?.f1 ?? 82.01,
                    },

                    {
                      label: "ROC AUC",
                      val:
                        allResults
                          ?.random_forest
                          ?.roc_auc ?? 74.3,
                    },

                    {
                      label: "Precision",
                      val:
                        allResults
                          ?.random_forest
                          ?.precision ?? 70.2,
                    },

                    {
                      label: "Recall",
                      val:
                        allResults
                          ?.random_forest
                          ?.recall ?? 98.58,
                    },
                  ].map((m) => (
                    <div
                      key={m.label}
                      className="bg-white/70 rounded-3xl p-5 flex justify-between items-center shadow"
                    >
                      <span className="text-slate-600 font-semibold">
                        {m.label}
                      </span>

                      <span className="text-2xl font-black text-slate-800">
                        {m.val?.toFixed
                          ? m.val.toFixed(1)
                          : m.val}
                        %
                      </span>
                    </div>
                  ))}
                </div>
              </div>

              {/* MLFLOW */}
              <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-6 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

                <div className="flex items-center gap-4">

                  <div className="w-16 h-16 rounded-3xl bg-gradient-to-br from-cyan-400 to-blue-500 flex items-center justify-center text-white text-2xl shadow-lg">
                    📡
                  </div>

                  <div>
                    <h3 className="font-black text-slate-800 text-lg">
                      MLflow Tracking
                    </h3>

                    <p className="text-slate-500">
                      localhost:5000
                    </p>
                  </div>

                  <div className="ml-auto w-4 h-4 bg-emerald-500 rounded-full animate-pulse shadow-lg" />
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ================= HISTORY ================= */}
        {navTab === "history" && (
          <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-8 shadow-[0_8px_40px_rgba(0,0,0,0.08)]">

            <TrainingResults
              results={allResults}
              onNotify={onNotify}
            />
          </div>
        )}
      </div>
    </div>
  );
}
